// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title ProofStore
 * @dev File provenance registry that ties file hashes with IPFS CIDs.
 */
contract ProofStore {
    uint256 private constant MAX_FILE_HASH_LENGTH = 66; // 0x + 64 hex chars
    uint256 private constant MAX_FILE_NAME_LENGTH = 256;
    uint256 private constant MAX_CONTENT_TYPE_LENGTH = 128;
    uint256 private constant MAX_CID_LENGTH = 128;

    struct Proof {
        address walletAddress;
        string fileHash;
        string fileName;
        uint256 fileSize;
        string contentType;
        string cid;
        uint256 timestamp;
    }

    // Proofs are keyed by (owner address + file hash) to prevent front-running.
    mapping(bytes32 => Proof) private proofs;

    // Track every hash each user has notarized.
    mapping(address => string[]) private userProofs;

    // Maintain historical ordering for each hash to keep the legacy getProof API working.
    mapping(string => bytes32[]) private proofKeysByHash;

    uint256 public totalProofs;

    event ProofCreated(
        address indexed walletAddress,
        string indexed fileHash,
        string cid,
        uint256 timestamp
    );

    /**
     * @dev Store a proof for the caller.
     */
    function storeProof(
        string memory _fileHash,
        string memory _fileName,
        uint256 _fileSize,
        string memory _contentType,
        string memory _cid
    ) public {
        _validateInputs(_fileHash, _fileName, _contentType, _cid);

        bytes32 proofKey = _proofKey(msg.sender, _fileHash);
        require(
            proofs[proofKey].timestamp == 0,
            "ProofStore: sender already stored this hash"
        );

        Proof memory newProof = Proof({
            walletAddress: msg.sender,
            fileHash: _fileHash,
            fileName: _fileName,
            fileSize: _fileSize,
            contentType: _contentType,
            cid: _cid,
            timestamp: block.timestamp
        });

        proofs[proofKey] = newProof;
        userProofs[msg.sender].push(_fileHash);
        proofKeysByHash[_fileHash].push(proofKey);
        totalProofs++;

        emit ProofCreated(msg.sender, _fileHash, _cid, block.timestamp);
    }

    /**
     * @dev Backward-compatible getter that returns the first proof ever recorded for a hash.
     */
    function getProof(
        string memory _fileHash
    ) public view returns (Proof memory) {
        bytes32[] storage keys = proofKeysByHash[_fileHash];
        require(keys.length > 0, "ProofStore: proof not found");
        return proofs[keys[0]];
    }

    /**
     * @dev Retrieve the proof stored by a specific wallet.
     */
    function getProofForUser(
        address _user,
        string memory _fileHash
    ) public view returns (Proof memory) {
        bytes32 proofKey = _proofKey(_user, _fileHash);
        require(
            proofs[proofKey].timestamp != 0,
            "ProofStore: proof not found"
        );
        return proofs[proofKey];
    }

    /**
     * @dev Return the list of hashes notarized by the provided wallet.
     */
    function getUserProofs(
        address _user
    ) public view returns (string[] memory) {
        return userProofs[_user];
    }

    /**
     * @dev Verify that the caller stored the hash and the CID matches.
     */
    function verifyProof(
        string memory _fileHash,
        string memory _cid
    ) public view returns (bool) {
        bytes32 proofKey = _proofKey(msg.sender, _fileHash);
        Proof storage proof = proofs[proofKey];
        if (proof.timestamp == 0) {
            return false;
        }

        return keccak256(bytes(proof.cid)) == keccak256(bytes(_cid));
    }

    function _validateInputs(
        string memory _fileHash,
        string memory _fileName,
        string memory _contentType,
        string memory _cid
    ) internal pure {
        bytes memory hashBytes = bytes(_fileHash);
        require(
            hashBytes.length > 0 && hashBytes.length <= MAX_FILE_HASH_LENGTH,
            "ProofStore: invalid file hash length"
        );
        require(
            bytes(_fileName).length <= MAX_FILE_NAME_LENGTH,
            "ProofStore: file name too long"
        );
        require(
            bytes(_contentType).length <= MAX_CONTENT_TYPE_LENGTH,
            "ProofStore: content type too long"
        );
        bytes memory cidBytes = bytes(_cid);
        require(
            cidBytes.length > 0 && cidBytes.length <= MAX_CID_LENGTH,
            "ProofStore: invalid cid length"
        );
    }

    function _proofKey(
        address _owner,
        string memory _fileHash
    ) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked(_owner, _fileHash));
    }
}
